final:
module MUX4X1 (
    input [3:0] mux_inputs,
    input [1:0] select_signals,
    output reg output_signal
);

always @ (*)
begin
    case ({select_signals})
        2'b00: output_signal = mux_inputs[0];
        2'b01: output_signal = mux_inputs[1];
        2'b10: output_signal = mux_inputs[2];
        2'b11: output_signal = mux_inputs[3];
        default: output_signal = 1'bx;
    endcase
end

endmodule
